selector_to_html = {"a[href=\"#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Key Features<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Multi-Source Integration<a class=\"headerlink\" href=\"#mc-input-source-list\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Input Source Configuration<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Priority Reference<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"../../example/Python.html#py-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.6 </span>Register custom input source<a class=\"headerlink\" href=\"#py-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, you must register an input source before controlling the MC. This example registers a custom input source via the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service so MC becomes aware of it; only registered input sources can perform robot velocity control.</strong></p>", "a[href=\"#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed programming examples and code explanations, refer to:</p>", "a[href=\"../../example/Cpp.html#cpp-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.6 </span>Register Secondary Development Input Source<a class=\"headerlink\" href=\"#cpp-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, an input source must be registered before controlling the MC. In this example, the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service is used to register the secondary development input source, so that the MC can recognize it. Only after registration can robot velocity control be performed.</strong></p>", "a[href=\"#mc\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.3 </span>MC Control Signal Configuration<a class=\"headerlink\" href=\"#mc\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>MC control signal configuration provides unified management of multiple input sources, ensuring the robot always responds to the highest-priority control signal.</strong></p><p>Control signal configuration is one of the core features of the AgiBot X2 AimDK, enabling unified management and priority arbitration among multiple control sources. This mechanism ensures that when multiple control inputs are active, the robot safely and reliably responds to the command with the highest priority.</p>", "a[href=\"#id6\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Arbitration Mechanism<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>Input Source Arbitration and Management Rules:</strong></p>", "a[href=\"#id4\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Priority Reference<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Arbitration Workflow<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Arbitration Mechanism<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>Input Source Arbitration and Management Rules:</strong></p>", "a[href=\"../../example/Cpp.html#cpp-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.7 </span>Get Current Input Source<a class=\"headerlink\" href=\"#cpp-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the GetCurrentInputSource service</strong>, which is used to obtain information about the currently registered input source, including the input source name, priority, and timeout settings.</p>", "a[href=\"#id9\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Notes<a class=\"headerlink\" href=\"#id9\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"../../example/Python.html#py-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.7 </span>Get current input source<a class=\"headerlink\" href=\"#py-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetCurrentInputSource</span></code> service</strong> to retrieve information about the currently registered input source, including name, priority, and timeout.</p>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Input Source Management Services<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#mc-input-source-list\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Multi-Source Integration<a class=\"headerlink\" href=\"#mc-input-source-list\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id2\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Priority Management<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
